import json
from collections import Counter
import re

# Get data
users_2016 = locals()['var_functions.query_db:72']
reviews = locals()['var_functions.query_db:10']
businesses = locals()['var_functions.query_db:66']

# Create mappings
user_ids = set([u['user_id'] for u in users_2016])
business_map = {}
for b in businesses:
    business_map[b['business_id']] = b

# Extract categories
def get_categories(desc):
    if not desc:
        return []

    categories = []
    desc_lower = desc.lower()

    if 'services in' in desc_lower:
        start = desc_lower.find('services in') + 11
        remaining = desc[start:]
        if '.' in remaining:
            remaining = remaining[:remaining.find('.')]

        parts = re.split(r',\s*|\s+and\s+', remaining)
        for part in parts:
            part = part.strip().rstrip('.').strip()
            if part and len(part) < 100:
                categories.append(part)

    elif 'including' in desc_lower:
        start = desc_lower.find('including') + 9
        remaining = desc[start:]
        if '.' in remaining:
            remaining = remaining[:remaining.find('.')]

        parts = re.split(r',\s*|\s+and\s+', remaining)
        for part in parts:
            part = part.strip().rstrip('.').strip()
            if part and len(part) < 100:
                categories.append(part)

    return categories

# Count reviews per category
category_counts = Counter()
matched = 0
reviews_per_biz = Counter()
biz_categories = {}

for review in reviews:
    ref = review['business_ref']
    if '_' in ref:
        num = ref.split('_')[1]
        biz_id = 'businessid_' + num

        reviews_per_biz[biz_id] += 1

        if biz_id in biz_categories:
            cats = biz_categories[biz_id]
        else:
            if biz_id in business_map:
                cats = get_categories(business_map[biz_id].get('description', ''))
                biz_categories[biz_id] = cats
            else:
                cats = []
                biz_categories[biz_id] = cats

        for cat in cats:
            category_counts[cat] += 1

        if biz_id in business_map:
            matched += 1

# Get top 5
top_5 = category_counts.most_common(5)

result = {
    'users_2016': len(users_2016),
    'reviews': len(reviews),
    'matched_reviews': matched,
    'unique_biz': len(reviews_per_biz),
    'categories_found': len(category_counts),
    'top_5': top_5
}

print('__RESULT__:')
print(json.dumps(result))

